import React from "react"
import { properties } from '../../properties/properties.js'


class CyberAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 0, result: []
        };
    }





    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/data`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []

        if (this.state.screen == 1) {


            header = ""

            if (this.state.result.HOTeams.length > 0) {

                content.push(<div style={{fontSize: "16px", color: "green"}}><br></br><u><b>Please assign the following patients</b></u><br></br>*** NOTE - in some cases the lists may have doubled patients, so the total number may be smaller than the sum of the lists. ***<br></br><br></br></div>)

            }





            content.push("Loaded")
        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
